#include "interface.h"
#include <vector>
#include <cstdint>

uint64_t run_end_sum(
    const std::vector<uint32_t>& run_ends,
    const std::vector<uint32_t>& values,
    int iters) {
  uint64_t total_sum = 0;
  const size_t n = values.size();
  if (n == 0) return 0;

  // Pre-calculate run lengths to avoid repeated subtraction in the inner loop
  // and to allow the compiler to vectorize the accumulation.
  // However, for maximum performance and minimal memory footprint, 
  // we can just compute it on the fly.

  for (int iter = 0; iter < iters; ++iter) {
    uint64_t current_iter_sum = 0;
    uint32_t prev_end = 0;

    for (size_t i = 0; i < n; ++i) {
      uint32_t current_end = run_ends[i];
      uint32_t run_len = current_end - prev_end;
      current_iter_sum += static_cast<uint64_t>(values[i]) * run_len;
      prev_end = current_end;
    }
    total_sum = current_iter_sum;
  }

  return total_sum;
}
